INSERT INTO `v1_0042bd9345e8b27b53dab5be0038aedea07f6df862fc099d2b181abb1e24937c` VALUES (0, 113511, 6, "あなた様のため…必ずや\n忘れられない最高の夏休みを\nお贈りいたしますわ…", 0, 11, 0, 1007001, 1007001042, 0, 1);
