INSERT INTO `v1_0042bd9345e8b27b53dab5be0038aedea07f6df862fc099d2b181abb1e24937c` VALUES (0, 113411, 8, "夏が来たら私たちのことを\n思い出しちゃうすっごい\nプロデュースをしちゃおうね！", 0, 11, 0, 1007001, 1007001047, 0, 1);
