INSERT INTO `v1_0042bd9345e8b27b53dab5be0038aedea07f6df862fc099d2b181abb1e24937c` VALUES (0, 113511, 7, "お姉ちゃんも弟くんの\n楽しそうな顔が見られて\nうれしかったよ！", 0, 11, 0, 1007007, 1007007023, 0, 1);
